    --form "issuing_agency_id=16"\
    --form "issuing_level_id=16"\
    --form "signer_id=16"\
    --form "document_type_ids[]=architecto"\
    --form "document_field_ids[]=architecto"\
    --form "ngay_ban_hanh=architecto"\
    --form "ngay_xuat_ban=architecto"\
    --form "ngay_hieu_luc=architecto"\
    --form "ngay_het_hieu_luc=architecto"\
    --form "status=architecto"\
