<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/meeting-vote-topics/16"
);

const headers = {
    "Authorization": "Bearer Bearer {YOUR_ACCESS_TOKEN}",
    "X-Organization-Id": "ID tổ chức cần làm việc (bắt buộc với endpoint yêu cầu auth). Example: 1",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "meeting_agenda_id": 16,
    "title": "Biểu quyết điều chỉnh kế hoạch",
    "vote_type": "approve_reject_abstain",
    "ballot_mode": "public_named",
    "show_result_on_projector": true,
    "show_result_on_personal_device": true,
    "sort_order": 39,
    "status": "opened"
};

fetch(url, {
    method: "PATCH",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>


