            'title' =&gt; 'Họp giao ban tuần',
            'is_public' =&gt; false,
            'content' =&gt; 'Nội dung chuẩn bị họp.',
            'start_time' =&gt; '2026-05-01 08:00:00',
            'end_time' =&gt; '2026-05-01 10:00:00',
            'status' =&gt; 'draft',
        ],
    ]
);
$body = $response-&gt;getBody();
print_r(json_decode((string) $body));</code></pre></div>

